sqlMap.select:
SELECT U.* FROM ( SELECT A.* FROM ( SELECT D.FOLDER_NAME1 AS FOLDERFILE_NAME, '' AS FILE_PATH, '' AS FILE_SIZE, '' AS TYPE_ID, D.FOLDER_TYPE AS FOLDER_TYPE, D.FOLDER_PATH AS FOLDER_PATH, D.USE_STATUS AS USE_STATUS, D.OWNER_ID AS OWNER_ID, D.CREATE_ID AS CREATE_ID, D.CREATE_DATE AS CREATE_DATE, D.COMPANY_ID AS COMPANY_ID, D.TENANT_ID AS TENANT_ID, S.SEQ_ID AS SEQ_ID, S.USER_ID AS USER_ID, S.USER_TYPE AS USER_TYPE, S.FOLDERFILE_ID AS FOLDERFILE_ID, S.FOLDERFILE_TYPE AS FOLDERFILE_TYPE FROM TBL_WEBFOLDER_FOLDER D, TBL_WEBFOLDER_SHARE S WHERE S.FOLDERFILE_TYPE = 'D' AND S.FOLDERFILE_ID = D.FOLDER_ID AND S.TENANT_ID = D.TENANT_ID AND ( (D.FOLDER_TYPE = 'C' AND D.OWNER_ID = #companyId#) OR (D.FOLDER_TYPE = 'D' AND D.OWNER_ID = #deptId#) OR (D.FOLDER_TYPE = 'U' AND D.OWNER_ID = #userId#) ) ) A
UNION ALL
SELECT B.* FROM ( SELECT F.FILE_NAME AS FOLDERFILE_NAME, F.FILE_PATH AS FILE_PATH, F.FILE_SIZE AS FILE_SIZE, F.TYPE_ID AS TYPE_ID, F.USE_STATUS AS USE_STATUS, F.CREATE_ID AS CREATE_ID, F.CREATE_DATE AS CREATE_DATE, F.TENANT_ID AS TENANT_ID, D.FOLDER_TYPE AS FOLDER_TYPE, D.FOLDER_PATH AS FOLDER_PATH, D.OWNER_ID AS OWNER_ID, D.COMPANY_ID AS COMPANY_ID, S.SEQ_ID AS SEQ_ID, S.USER_ID AS USER_ID, S.USER_TYPE AS USER_TYPE, S.FOLDERFILE_ID AS FOLDERFILE_ID, S.FOLDERFILE_TYPE AS FOLDERFILE_TYPE FROM TBL_WEBFOLDER_FILE F, TBL_WEBFOLDER_SHARE S, TBL_WEBFOLDER_FOLDER D WHERE S.FOLDERFILE_TYPE = 'F' AND S.FOLDERFILE_ID = F.FILE_ID AND S.TENANT_ID = F.TENANT_ID AND F.FOLDER_ID = D.FOLDER_ID AND F.TENANT_ID = D.TENANT_ID AND ( (D.FOLDER_TYPE = 'C' AND D.OWNER_ID = #companyId#) OR (D.FOLDER_TYPE = 'D' AND D.OWNER_ID = #deptId#) OR (D.FOLDER_TYPE = 'U' AND D.OWNER_ID = #userId#) ) ) B ) U ;

SELECT U.* FROM ( SELECT A.* FROM ( SELECT D.FOLDER_NAME1 AS FOLDERFILE_NAME, '' AS FILE_PATH, '' AS FILE_SIZE, '' AS TYPE_ID, D.FOLDER_TYPE AS FOLDER_TYPE, D.FOLDER_PATH AS FOLDER_PATH, D.USE_STATUS AS USE_STATUS, D.OWNER_ID AS OWNER_ID, D.CREATE_ID AS CREATE_ID, D.CREATE_DATE AS CREATE_DATE, D.COMPANY_ID AS COMPANY_ID, D.TENANT_ID AS TENANT_ID, S.SEQ_ID AS SEQ_ID, S.USER_ID AS USER_ID, S.USER_TYPE AS USER_TYPE, S.FOLDERFILE_ID AS FOLDERFILE_ID, S.FOLDERFILE_TYPE AS FOLDERFILE_TYPE FROM TBL_WEBFOLDER_FOLDER D, TBL_WEBFOLDER_SHARE S WHERE S.FOLDERFILE_TYPE = 'D' AND S.FOLDERFILE_ID = D.FOLDER_ID AND S.TENANT_ID = D.TENANT_ID AND ( (S.USER_TYPE = 'C' AND S.USER_ID = #companyId#) OR (S.USER_TYPE = 'D' AND S.USER_ID = #deptId#) OR (S.USER_TYPE = 'U' AND S.USER_ID = #userId#) ) ) A
UNION ALL
SELECT B.* FROM ( SELECT F.FILE_NAME AS FOLDERFILE_NAME, F.FILE_PATH AS FILE_PATH, F.FILE_SIZE AS FILE_SIZE, F.TYPE_ID AS TYPE_ID, F.USE_STATUS AS USE_STATUS, F.CREATE_ID AS CREATE_ID, F.CREATE_DATE AS CREATE_DATE, F.TENANT_ID AS TENANT_ID, D.FOLDER_TYPE AS FOLDER_TYPE, D.FOLDER_PATH AS FOLDER_PATH, D.OWNER_ID AS OWNER_ID, D.COMPANY_ID AS COMPANY_ID, S.SEQ_ID AS SEQ_ID, S.USER_ID AS USER_ID, S.USER_TYPE AS USER_TYPE, S.FOLDERFILE_ID AS FOLDERFILE_ID, S.FOLDERFILE_TYPE AS FOLDERFILE_TYPE FROM TBL_WEBFOLDER_FILE F, TBL_WEBFOLDER_SHARE S, TBL_WEBFOLDER_FOLDER D WHERE S.FOLDERFILE_TYPE = 'F' AND S.FOLDERFILE_ID = F.FILE_ID AND S.TENANT_ID = F.TENANT_ID AND F.FOLDER_ID = D.FOLDER_ID AND F.TENANT_ID = D.TENANT_ID AND ( (S.USER_TYPE = 'C' AND S.USER_ID = #companyId#) OR (S.USER_TYPE = 'D' AND S.USER_ID = #deptId#) OR (S.USER_TYPE = 'U' AND S.USER_ID = #userId#) ) ) B
) U;
